+function current(world: World): DeferredCommand[] {
+    const scopes = world[$internal].deferred.scopes;
+    return scopes[scopes.length - 1];
+}
+
+export function beginDeferredScope(world: World) {
+    world[$internal].deferred.scopes.push([]);
+}
+
+export function endDeferredScope(world: World) {
+    flushDeferred(world, current(world));
+    world[$internal].deferred.scopes.pop();
+}
+
+export function hasPendingDeferred(world: World, entity: Entity) {
+    return commands(world).some((command) => command.entity === entity);
+}
+
+export function flushPendingDeferred(world: World, entity: Entity) {
+    if (hasPendingDeferred(world, entity)) flushDeferred(world, current(world));
+}
