+/** The projected membership used by entity.has while commands are waiting. */
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): boolean {
+    let value = isRelationPair(trait)
+        ? trait[$internal].target === '*'
+            ? getRelationTargets(world, trait[$internal].relation, entity).length > 0
+            : getRelationTargets(world, trait[$internal].relation, entity).includes(trait[$internal].target as Entity)
+        : hasTrait(world, entity, trait);
+
+    for (const command of commands(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') return false;
+        if (command.type === 'remove') {
+            for (const candidate of command.traits) {
+                if (sameTrait(candidate, trait)) value = false;
+            }
+        } else if (command.type === 'add' || command.type === 'spawn' || command.type === 'addExclusive') {
+            for (const candidate of command.traits) {
+                if (sameTrait(candidate, trait)) value = !isRelationPair(candidate) || candidate[$internal].target !== '*';
+                if (command.type === 'addExclusive' && isRelationPair(candidate) && isRelationPair(trait) &&
+                    candidate[$internal].relation === trait[$internal].relation && candidate[$internal].target !== trait[$internal].target) {
+                    value = false;
+                }
+            }
+        }
+    }
+    return value;
+}
+
+function sameTrait(a: ConfigurableTrait | Trait | RelationPair, b: Trait | RelationPair) {
+    const aTrait = isRelationPair(a) ? a[$internal].relation[$internal].trait : Array.isArray(a) ? a[0] : a;
+    const bTrait = isRelationPair(b) ? b[$internal].relation[$internal].trait : b;
+    if (aTrait !== bTrait) return false;
+    if (!isRelationPair(a) || !isRelationPair(b)) return true;
+    return a[$internal].target === '*' || b[$internal].target === '*' || a[$internal].target === b[$internal].target;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
+    let value = getTrait(world, entity, trait);
+    for (const command of commands(world)) {
+        if (command.entity !== entity || command.type === 'destroy') continue;
+        if (command.type === 'remove' && command.traits.some((candidate) => sameTrait(candidate, trait))) value = undefined;
+        if (command.type === 'add' || command.type === 'spawn' || command.type === 'addExclusive') {
+            for (const candidate of command.traits) {
+                if (!sameTrait(candidate, trait)) continue;
+                if (isRelationPair(candidate)) value = candidate[$internal].params ?? value ?? {};
+                else if (Array.isArray(candidate)) value = candidate[1];
+            }
+        }
+    }
+    return hasDeferredTrait(world, entity, trait) ? value : undefined;
+}
