+        add(entity, ...traits) { defer({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { defer({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) { defer({ type: 'addExclusive', entity, traits }); },
+        flush() { flushDeferred(world, current(world)); },
+    };
